    int maxLen = 0;
    int endIndex = m;

    for (int I = 0; I <= m; i++)
    {
        for (int j = 0; j <= n; j++)
        {
            if (i == 0 || j == 0)
                arr[i][j] = 0;
            else if (str1[i - 1] == str2[j - 1])
            {
                arr[i][j] = arr[i - 1][j - 1] + 1;
                if (arr[i][j] > maxLen)
                {
                    maxLen = arr[i][j];
                    endIndex = i;
                }
            }
            else
                arr[i][j] = 0;
        }
    }

