        Node newNode = new Node(data);
        if (head == null) {
            head = newNode;
        } else {
            Node trm = head;
            while (trm.next != null) {
                trm = trm.next;
            }
            trm.next = newNode;
        }
    }

    public void addAtPosition(int position, int data) {
        if (position == 0) {
            addBeginning(data);
            return;
        }

        Node newNode = new Node(data);
        Node current = head;
        int currentPosition = 0;

        while (current != null && currentPosition < position - 1) {
            current = current.next;
            currentPosition++;
        }

        if (current == null) {
            return;
        }

        newNode.next = current.next;
        current.next = newNode;
    }

    public void reverse() {
        Node prev = null;
        Node current = head;
        Node nextNode;
        while (current != null) {
            nextNode = current.next;
            current.next = prev;
            prev = current;
            current = nextNode;
