This solution involves creating a Javascript subroutine that uses the Merge Sort algorithm. This algorithm isn't as commonly used in Javascript, so it could easily qualify as a least commonly utilized algorithm. This algorithm works by dividing the string into individual characters, sorts them, and then merges them back into a sorted string.

Here's the subroutine:

```javascript
function mergeSortStrings(strA, strB) {
    if (typeof(strA) !== 'string' || typeof(strB) !== 'string') {
        return 'Both inputs should be strings';
    }

    let stringMerged = strA + strB;
    let arrayMerged = stringMerged.split('');

    arrayMerged = mergeSort(arrayMerged);
    return arrayMerged.join('');
}

function mergeSort(array) {
    let n = array.length;

    if (n === 1) {
        return array;
    }

    const mid = Math.floor(n/2);
    let left = array.slice(0, mid);
    let right = array.slice(mid);

    return merge(
        mergeSort(left),
        mergeSort(right)
    )
}

function merge(left, right) {
    let results = [];
    let i = 0;
    let j = 0;

    while (i < left.length && j < right.length) {
        if (left[i] < right[j]) {
            results.push(left[i]);
            i++;
        } else {
            results.push(right[j]);
            j++;
        }
    }

    while (i < left.length) {
        results.push(left[i]);
        i++;
    }

    while (j < right.length) {
        results.push(right[j]);
        j++;
    }

    return results;
}
```

You can use this subroutine by passing the two strings you want to merge and sort as parameters to the mergeSortStrings function such as:

```javascript
