import Foundation

class Solution {

    func activateOrderingBySum(_ nums: [Int]) -> [Int] {
        return nums.sorted {
            let absA = abs($0)
            let absB = abs($1)

            let sumA = self.calcDigitSum(absA)
            let sumB = self.calcDigitSum(absB)

            return sumA < sumB || (sumA == sumB && absA < absB)
        }
    }

    func calcDigitSum(_ n: Int) -> Int {
        var num = n
        var sum = 0
        while num != 0 {
            sum += num % 10
            num /= 10
        }
        return sum
    }

}

