```c++
#include<bits/stdc++.h>
using namespace std;

bool isPrime(int n) 
{  
    if(n<=1) 
        return false;
    if(n==2)
        return true;
    if(n%2==0)
        return false;
    for(int i=3; i*i<=n; i+=2) 
    {
        if(n%i==0)
            return false;
    }
    return true;
} 

int main() 
{ 
    int n = 50;
    cout << "Prime numbers up to " << n << " are: ";
    for(int i=0; i<=n; i++) 
    {
        if (isPrime(i)) 
            cout << i << " ";
    }
    return 0;
}
