def select_words(s, n):
    if not s:
        return []

    def count_consonants(word):
        return sum(1 for c in word if c.lower() in "bcdfghjklmnpqrstvwxyz")

    words = s.split()
    selected = []
    for word in words:
        if count_consonants(word) == n:
            if selected and count_consonants(selected[-1]) == n:
                selected[-1] += word
            else:
                selected.append(word)

    return selected

