#include <iostream>
using namespace std;

void sortArray(int arr[], int arr_size) {
    int i, j;
    for (i = 0; i < arr_size-1; i++) {
        for (j = 0; j < arr_size-i-1; j++) {  
            if (arr[j] > arr[j+1]) {
                // Swap arr[j] and arr[j+1]
                int temp = arr[j];
                arr[j] = arr[j+1];
                arr[j+1] = temp;
            }
        }
    }
}

