void optimizeMatrix (vector<vector<int>> &mat, int val) { 
  // Iterate over the matrix
  for (int i = 0; i < mat.size(); i++) { 
    for (int j = 0; j < mat[i].size(); j++) { 
      // Substitute all elements to be 
      // greater than or equal to value
      if (mat[i][j] < val) 
