def valid_sudoku(board):
    # Row check
    for row in board:
        if sorted(row) != [1,2,3,4,5,6,7,8,9]:
            return False

    # Column check
    for col in list(zip(*board)):
        if sorted(col) != [1,2,3,4,5,6,7,8,9]:
            return False

    # 3x3 check
    for i in [0,3,6]:
        for j in [0,3,6]:
            subset = [board[x][y] for x in range(i,i+3) for y in range(j,j+3)]
            if sorted(subset) != [1,2,3,4,5,6,7,8,9]:
                return False

    # If everything passes, the board is valid
    return True

