def max_thermometer_reading(l):
    '''This function computes the maximum thermometer reading given as a list of strings'''
    order = {'F': 0, 'C': 1}
    max_val = float('-inf')
    for reading in l:
        num, unit = reading[:-1], reading[-1]
        if order[unit] > order[max_val[-1]]:
            max_val = reading
        elif order[unit] == order[max_val[-1]]:
            if float(max_val[:-1]) < float(num):
                max_val = reading
    return max_val

