public class SineWave extends Applet {
 int xs, ys;
 int h = 0;
 double scale, freq, constVal;

 public void init() {
 xs = getSize().width - 1;
 ys = getSize().height - 1;
 scale = (double) xs;
 freq = Math.PI / scale;
 }

 public void paint(Graphics g) {
 g.drawLine(0, ys/2, xs, ys/2);
 for (int i = 0; i <= xs; i++) {
 constVal = (double) ys/2 * Math.sin(i * freq + h);
 g.drawLine(i, (int) (ys/2 - constVal), i, (int) (ys/2 + constVal));
 }
 h = h - 1;
 try {
 Thread.sleep(100);
 }
 catch (InterruptedException e) {}
 repaint();
 }
}

