void bubbleSort(vector<int> &num) { 
    int i, j, temp; 
    int size = num.size();

    for (i = 0; i < size-1; i++) {     

        for (j = 0; j < size-i-1; j++) {  
            if (num[j] > num[j+1]) { 
                temp = num[j]; 
                num[j] = num[j+1]; 
                num[j+1] = temp; 
            } 
        } 
    } 
} 

