public static int fibonacci(int n)
{
    if (n == 0)
        return 0;
    if (n == 1)
        return 1;
    int f = 0;
    int a = 0;
    int b = 1;
    for (int i = 2; i <= n; i++)
    {
        f = a + b;
        a = b;
        b = f;
    }
    return f;
}

def build_decision_tree(data):
    labels = data[0]
    tree = {labels[0]:{}} 
    for i, row in enumerate(data[1:]):
        current_node = tree[labels[0]]
        for j, column in enumerate(row):
            if column not in current_node:
                if j + 1 != len(row):
                    current_node[column] = {}
                    current_node = current_node[column]
                else:
                    current_node[column] = row[-1]

    return tree

